var e=[{id:`L4_1`,type:`dialog`,speaker:`OGRE1_NPC_NULL_NULL`,text:{KOREA:`크오오오!`,JPN:`グオオオオオ！`,ENG:`Kkkohhhhh!`,TWN:`唔吼吼吼！`},stage:{bg:`SUMMER_BEACH_NIGHT`,bgm:`BATTLE_NORMAL_04`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}},sfx:`FX_COMBAT_MONSTER_BEAST_VOICE_36`},{id:`L5_1`,type:`dialog`,speaker:`OGRE2_NPC_NULL_NULL`,text:{KOREA:`캬오오오!`,JPN:`ギャオオ！`,ENG:`Kyaaaooooh!`,TWN:`嘎吼吼吼！`},stage:{bg:`SUMMER_BEACH_NIGHT`,bgm:`BATTLE_NORMAL_04`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}},sfx:`FX_COMBAT_MONSTER_BEAST_VOICE_35`},{id:`L6_1`,type:`dialog`,speaker:`RIFLE_FOX_ENEMY_BOSS`,text:{KOREA:`계속 밀어붙여! 침식체들을 이용해!`,JPN:`追い詰めろ！　侵食体を利用するんだ！`,ENG:`Keep pushing! Use the C.O.s!`,TWN:`繼續推進！利用侵蝕體！`},stage:{bg:`SUMMER_BEACH_NIGHT`,bgm:`BATTLE_NORMAL_04`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`RIFLE_FOX_ENEMY_BOSS`,face:`UNIT_IDLE`},R:null}},sfx:`FX_CUTSCEN_FOOTSTEP_RUNNING_02`},{id:`L7_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_SUMMER_NULL`,text:{KOREA:`크윽, 저 녀석들 침식체들하고 한 편이라도 된 것처럼 몰려오잖아? 어떻게 된 거지?`,JPN:`くっ、あいつら侵食体と手を組んだかのように押し寄せてくる。どうなってるの？`,ENG:`Ugh, it's as if they're working together with the C.O.s. What's going on?`,TWN:`唔，那些傢伙為什麼和侵蝕體一起衝過來？這是怎麼回事？`},stage:{bg:`SUMMER_BEACH_NIGHT`,bgm:`BATTLE_NORMAL_04`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_SUMMER_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`ELIZABETH_PRYDWEN_SUMMER_NULL`,text:{KOREA:`흥, 사람이 침식체와 손을 잡다니, 비겁하고 저열하기 짝이 없군요.`,JPN:`ふん、人が侵食体と手を組むなんて、卑怯で低俗すぎますわ。`,ENG:`Hmpf, they're in league with the C.O.s? How mean and cowardly!`,TWN:`哼，人類竟然與侵蝕體合作，真是卑鄙至極。`},stage:{bg:`SUMMER_BEACH_NIGHT`,bgm:`BATTLE_NORMAL_04`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ELIZABETH_PRYDWEN_SUMMER_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`RIFLE_FOX_ENEMY_BOSS`,text:{KOREA:`바로 그것이 우리 찰거머리 특전대의 방식이지! 칭찬 고맙군!`,JPN:`まさにそれが粘着特戦隊のやり方だ！　褒め言葉として受け取っておこう！`,ENG:`The two words that best represent the Leech Rangers! Thank you for the compliment!`,TWN:`這正是我們血蛭特戰隊的作風！謝謝誇獎！`},stage:{bg:`SUMMER_BEACH_NIGHT`,bgm:`BATTLE_NORMAL_04`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`RIFLE_FOX_ENEMY_BOSS`,face:`UNIT_IDLE`},R:null}},sfx:`FX_CUTSCEN_BOOM_REPEAT`},{id:`L12_1`,type:`dialog`,speaker:`LONELY_NPC_SUMMER_NULL`,text:{KOREA:`우후후...... 상황이 이렇게 순조롭게 흘러가다니.`,JPN:`うふふ……こうも順調に進むなんて。`,ENG:`Hah hah hah... Things are going my way.`,TWN:`呵呵……沒想到事情進展地這麼順利。`},stage:{bg:`SUMMER_BEACH_NIGHT`,bgm:`BATTLE_NORMAL_04`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LONELY_NPC_SUMMER_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`LONELY_NPC_SUMMER_NULL`,text:{KOREA:`이대로라면 섬을 지배하고 나만의 하렘 왕국을 건설할 수도 있겠어!`,JPN:`このまま行けば、島を支配して私だけのハーレム王国を作れる！`,ENG:`At this rate, I can even conquer the island and build a harem for myself!`,TWN:`這樣下去，我就可以統治這座島嶼，還能建立我的後宮王國了！`},stage:{bg:`SUMMER_BEACH_NIGHT`,bgm:`BATTLE_NORMAL_04`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LONELY_NPC_SUMMER_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`OGRE2_NPC_NULL_NULL`,text:{KOREA:`(검은 머리 여자! 우리! 함께 한다!)`,JPN:`(黒髪の女！　俺たち！　一緒だ！)`,ENG:`(Black-haired female! She's with us!)`,TWN:`（黑髮女！我們！一起！）`},stage:{bg:`SUMMER_BEACH_NIGHT`,bgm:`BATTLE_NORMAL_04`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LONELY_NPC_SUMMER_NULL`,face:`UNIT_IDLE`},R:null}},sfx:`FX_COMBAT_MONSTER_BEAST_VOICE_36`},{id:`L16_1`,type:`dialog`,speaker:`OGRE1_NPC_NULL_NULL`,text:{KOREA:`(좋다! 좋다!)`,JPN:`(一緒だ！　一緒だ！)`,ENG:`(Yes! Yesss!)`,TWN:`（好耶！好耶！）`},stage:{bg:`SUMMER_BEACH_NIGHT`,bgm:`BATTLE_NORMAL_04`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LONELY_NPC_SUMMER_NULL`,face:`UNIT_IDLE`},R:null}},sfx:`FX_COMBAT_MONSTER_BEAST_VOICE_35`}];export{e as default};